def count_pos_neg(arr):
    positive = 0
    negative = 0

    for num in arr:
        if num > 0:
            positive += 1
        elif num < 0:
            negative += 1

    return {'positive': positive, 'negative': negative}

print(count_pos_neg([3, -1, 0, -5, 8]))

def range_sum(arr, left, right):
    prefix = []
    running = 0

    for num in arr:
        running += num
        prefix.append(running)

    if left == 0:
        return prefix[right]

    return prefix[right] - prefix[left - 1]

print(range_sum([2, 4, 1, 3, 6], 1, 3))

def max_sum_three(arr):
    best = arr[0] + arr[1] + arr[2]

    for i in range(1, len(arr) - 2):
        current = arr[i] + arr[i + 1] + arr[i + 2]
        if current > best:
            best = current

    return best

print(max_sum_three([2, 1, 5, 1, 3, 2]))

def count_even_sum_pairs(arr):
    count = 0

    for i in range(len(arr)):
        for j in range(i + 1, len(arr)):
            if (arr[i] + arr[j]) % 2 == 0:
                count += 1

    return count

print(count_even_sum_pairs([1, 2, 3, 4]))

def move_zeroes(arr):
    result = []
    zero_count = 0

    for num in arr:
        if num == 0:
            zero_count += 1
        else:
            result.append(num)

    for i in range(zero_count):
        result.append(0)

    return result

print(move_zeroes([0, 1, 0, 3, 12]))

def max_sum_k(arr, k):
    if k <= 0 or k > len(arr):
        return None

    current = 0
    for i in range(k):
        current += arr[i]

    best = current

    for i in range(k, len(arr)):
        current += arr[i]
        current -= arr[i - k]
        if current > best:
            best = current

    return best

print(max_sum_k([2, 1, 5, 1, 3, 2], 3))

def first_repeating(arr):
    seen = set()

    for num in arr:
        if num in seen:
            return num
        seen.add(num)

    return None

print(first_repeating([4, 2, 5, 2, 4]))

def longest_word(sentence):
    words = sentence.split()
    best = ''

    for word in words:
        if len(word) > len(best):
            best = word

    return best

print(longest_word('python makes problem solving joyful'))

def char_count(s):
    freq = {}
    for ch in s:
        if ch == ' ':
            continue
        ch = ch.lower()
        freq[ch] = freq.get(ch, 0) + 1
    return freq


def are_anagrams(a, b):
    return char_count(a) == char_count(b)

print(are_anagrams('Listen', 'Silent'))

def subarray_with_sum(arr, target):
    left = 0
    current = 0

    for right in range(len(arr)):
        current += arr[right]

        while current > target and left <= right:
            current -= arr[left]
            left += 1

        if current == target:
            return True

    return False

print(subarray_with_sum([1, 4, 20, 3, 10, 5], 33))

def min_subarray_len(arr, target):
    left = 0
    current = 0
    best = None

    for right in range(len(arr)):
        current += arr[right]

        while current >= target:
            length = right - left + 1
            if best is None or length < best:
                best = length
            current -= arr[left]
            left += 1

    if best is None:
        return 0
    return best

print(min_subarray_len([2, 3, 1, 2, 4, 3], 7))

def window_maximums(arr, k):
    result = []

    for start in range(0, len(arr) - k + 1):
        biggest = arr[start]
        for i in range(start, start + k):
            if arr[i] > biggest:
                biggest = arr[i]
        result.append(biggest)

    return result

print(window_maximums([1, 3, -1, -3, 5, 3, 6, 7], 3))
